// Input: full GitHub trending HTML in $json.body
// Output: clean HTML containing only repo list section

// Get HTML from incoming data
const html = $json.body || $json.data || "";

// Safety: if nothing found, return empty
if (!html) {
  return [{
    clean_html: ""
  }];
}

// GitHub Trending repo list lives inside <article> tags
const repoSectionRegex = /<article[\s\S]*?<\/article>/g;

// Extract all <article> blocks
const matches = html.match(repoSectionRegex) || [];

// Join them into clean HTML
const cleanHtml = matches.join("\n\n");

return [{
  clean_html: cleanHtml
}];

// Input: { clean_html: "<article>...</article> ..." }
// Output: array of repos with only Name, Link, Description, Language, Stars

const cleanHtml = $json.clean_html || "";
if (!cleanHtml) {
  return [];
}

// Split into individual <article> blocks
const articles = cleanHtml.split(/<\/article>/).map(a => a.trim()).filter(a => a);

// Helper to extract with regex
function extract(re, str) {
  const m = re.exec(str);
  return m ? m[1].trim() : "";
}

const repos = articles.map(article => {
  const name = extract(/<h2[^>]*>\s*<a[^>]*>([\s\S]*?)<\/a>/, article)
    .replace(/\s+/g, " ") // normalize spacing
    .trim();

  const link = extract(/<h2[^>]*>\s*<a[^>]*href="([^"]+)"/, article);
  const desc = extract(/<p[^>]*>([\s\S]*?)<\/p>/, article)
    .replace(/<[^>]+>/g, "") // strip tags
    .trim();

  const language = extract(/itemprop="programmingLanguage">([^<]+)</, article);

  const stars = extract(/stargazers"[^>]*>[\s\S]*?<\/svg>\s*([\d,]+)/, article);

  return {
    json: {
      Name: name,
      Link: link ? "https://github.com" + link : "",
      Description: desc,
      Language: language,
      Stars: stars
    }
  };
});

return repos;

// Build nicer HTML for email (card style)
const blocks = items.map(i => `
  <div style="border:1px solid #ddd; border-radius:8px; padding:12px; margin:10px 0; font-family:Arial, sans-serif;">
    <h3 style="margin:0 0 6px 0; font-size:16px; color:#0366d6;">
      <a href="${i.json.Link}" style="text-decoration:none; color:#0366d6;">${i.json.Name}</a>
    </h3>
    <p style="margin:4px 0 8px 0; color:#555;">${i.json.Description}</p>
    <p style="margin:0; font-size:14px;">
      <strong>Language:</strong> ${i.json.Language} &nbsp;|&nbsp;
      ⭐ <strong>${i.json.Stars}</strong>
    </p>
  </div>
`).join("\n");

return [{
  json: {
    html: `<div style="max-width:600px; margin:auto;">${blocks}</div>`
  }
}];
